#include <bits/stdc++.h>
using namespace std;

class Solution {
public:
    // Function to perform DFS traversal
    void dfs(int v, vector<int> adj[], 
             vector<int>& visited, 
             vector<int>& result) {

        // Mark current node as visited
        visited[v] = 1;

        // Store node in result
        result.push_back(v);

        // Traverse all neighbours
        for (int u : adj[v]) {
            if (!visited[u]) {
                dfs(u, adj, visited, result);
            }
        }
    }
};

int main() {
    // Number of vertices
    int V;
    cin >> V;

    // Adjacency list
    vector<int> adj[V];
    for (int i = 0; i < V; i++) {
        int numNeighbors;
        cin >> numNeighbors;
        for (int j = 0; j < numNeighbors; j++) {
            int neighbor;
            cin >> neighbor;
            adj[i].push_back(neighbor);
        }
    }

    // Visited array
    vector<int> visited(V, 0);

    // Result vector
    vector<int> result;

    // Create object
    Solution sol;

    // Run DFS from node 0
    sol.dfs(0, adj, visited, result);

    // Print traversal
    for (int x : result) cout << x << " ";
    cout << endl;

    return 0;
}

